type ServerData = {
    id: string;
    url: string;
    authorization: {
        status: "not_required" | "discovery_failed" | "requires_registration" | "requires_connection" | "connected";
        protectedResourceMetadata: any;
        protectedResourceMetadataError: string | null;
        authorizationServerUrl: string;
        authorizationServerMetadata: any;
        authorizationServerError: string | null;
        unauthedWwwAuthenticate: string | null;
        unauthedStatusCode: number | null;
        registrationError: string | null;
    };
    hasAccessToken?: boolean;
};
declare const useToolbox: (toolboxUrl?: string) => {
    toolbox: {
        servers: (ServerData & {
            retryDiscovery: () => Promise<void>;
            generateAuthorizationUrl: (scopes?: string[], finalRedirectUrl?: string) => Promise<{
                authorizationUrl: string;
            } | {
                error: string;
            }>;
        })[];
        addServer: (data: FormData) => Promise<void>;
    };
    isLoaded: boolean;
};

export { useToolbox };
